// src/better-auth/utils/omitProtectedBodyFields.ts
import { z } from "zod/v4";
var PROTECTED_BODY_FIELD_NAMES = ["customerId", "customerData"];
var getProtectedShape = ({
  schema
}) => {
  const omitShape = {};
  for (const fieldName of PROTECTED_BODY_FIELD_NAMES) {
    if (fieldName in schema.shape) {
      omitShape[fieldName] = true;
    }
  }
  return omitShape;
};
var omitProtectedBodyFields = ({
  schema
}) => {
  if (!(schema instanceof z.ZodObject)) {
    return schema;
  }
  const omitShape = getProtectedShape({ schema });
  if (Object.keys(omitShape).length === 0) {
    return schema;
  }
  return schema.omit(omitShape);
};

export {
  omitProtectedBodyFields
};
